#include "config.h"

#include <stdlib.h>
#include <string.h>

#include <libgimp/ammoos.h>
#include <libgimp/gimpui.h>

#include "libgimp/stdplugins-intl.h"

#include "gfig.h"
#include "gfig-dobject.h"
