  gtk_container_add (GTK_CONTAINER (frame), tmpw);
  gtk_widget_set_visible (tmpw, TRUE);

  paper_invert = tmpw = gtk_check_button_new_with_mnemonic ( _("_Invert"));
  gtk_box_pack_start (GTK_BOX (box2), tmpw, FALSE, FALSE, 0);
