   browse = browse_widget_new( _("Select HTML file"));
   browse_widget_set_filter(browse, relative_filter, (gpointer) dialog);
   gtk_grid_attach (GTK_GRID (grid), browse->hbox, 0, 3, 1, 1);
   dialog->url = browse->file;
