#include <libgimp/gimpui.h>

#include "imap_file.h"
#include "imap_main.h"

#include "libgimp/stdplugins-intl.h"


static void
open_cb (GtkNativeDialog *dialog,
         gint             response_id,
         gpointer         data)
{
  if (response_id == GTK_RESPONSE_ACCEPT)
    {
      gchar *filename;

      filename = gtk_file_chooser_get_filename (GTK_FILE_CHOOSER (dialog));

      if (! g_file_test (filename, G_FILE_TEST_IS_REGULAR))
        {
          do_file_error_dialog (_("Error opening file"), filename);
          g_free (filename);
          return;
        }

      load (filename, data);
      g_free (filename);
    }

  gtk_native_dialog_hide (dialog);
}

void
do_file_open_dialog (GSimpleAction *action,
                     GVariant      *parameter,
                     gpointer       user_data)
{
  static GtkFileChooserNative *dialog;
  GtkFileFilter               *filter;

  if (! dialog)
    {
      dialog =
        gtk_file_chooser_native_new (_("Load Image Map"),
                                     NULL,
                                     GTK_FILE_CHOOSER_ACTION_OPEN,
                                     _("_Open"), _("_Cancel"));

      filter = gtk_file_filter_new ();
      gtk_file_filter_set_name (filter, _("All Files"));
      gtk_file_filter_add_pattern (filter, "*");
      gtk_file_chooser_add_filter (GTK_FILE_CHOOSER (dialog), filter);

      filter = gtk_file_filter_new ();
      gtk_file_filter_set_name (filter, _("Map file (*.map)"));
      gtk_file_filter_add_pattern (filter, "*.map");
      gtk_file_filter_add_pattern (filter, "*.MAP");
      gtk_file_chooser_add_filter (GTK_FILE_CHOOSER (dialog), filter);

      gtk_file_chooser_set_filter (GTK_FILE_CHOOSER (dialog), filter);

      g_signal_connect (dialog, "response",
                        G_CALLBACK (open_cb),
                        user_data);
    }

  gtk_native_dialog_show (GTK_NATIVE_DIALOG (dialog));
}

static void
save_cb (GtkNativeDialog *dialog,
         gint             response_id,
         gpointer         data)
{
  if (response_id == GTK_RESPONSE_ACCEPT)
    {
      gchar *filename;

      filename = gtk_file_chooser_get_filename (GTK_FILE_CHOOSER (dialog));

      save_as (filename);
      g_free (filename);
    }

  gtk_native_dialog_hide (dialog);
}

void
do_file_save_as_dialog (GSimpleAction *action,
                        GVariant      *parameter,
                        gpointer       user_data)
{
  static GtkFileChooserNative *dialog;
  GtkFileFilter               *filter;

  if (! dialog)
    {
      gchar *filename;

      dialog = gtk_file_chooser_native_new (_("Save Image Map"),
                                            NULL,
                                            GTK_FILE_CHOOSER_ACTION_SAVE,
                                            _("_Save"), _("_Cancel"));

      gtk_file_chooser_set_do_overwrite_confirmation (GTK_FILE_CHOOSER (dialog),
                                                      TRUE);

      filter = gtk_file_filter_new ();
      gtk_file_filter_set_name (filter, "Map (*.map)");
      gtk_file_filter_add_pattern (filter, "*.map");
      gtk_file_filter_add_pattern (filter, "*.MAP");
      gtk_file_chooser_add_filter (GTK_FILE_CHOOSER (dialog), filter);

      g_signal_connect (dialog, "response",
                        G_CALLBACK (save_cb),
                        dialog);

      /*  Suggest a filename based on the image name.
       *  The image name is in UTF-8 encoding.
       */
      filename = g_strconcat (get_image_name(), ".map", NULL);

      if (filename)
        {
          gtk_file_chooser_set_current_name (GTK_FILE_CHOOSER (dialog),
                                             filename);
          g_free (filename);
        }
    }

  gtk_native_dialog_show (GTK_NATIVE_DIALOG (dialog));
}

void
do_file_error_dialog (const char *error,
                      const char *filename)
{
   GtkWidget *dialog;

   dialog = gtk_message_dialog_new_with_markup
     (NULL,
      GTK_DIALOG_DESTROY_WITH_PARENT,
      GTK_MESSAGE_ERROR,
      GTK_BUTTONS_CLOSE,
      "<span weight=\"bold\" size=\"larger\">%s</span>\n\n%s",
      error,
      gimp_filename_to_utf8 (filename));

   g_signal_connect_swapped (dialog, "response",
                             G_CALLBACK (gtk_widget_destroy),
                             dialog);
   gtk_dialog_run (GTK_DIALOG (dialog));
}

