void
mapobject_icons_init (void)
{
  static gboolean initialized = FALSE;

  GtkIconTheme *icon_theme;

  if (initialized)
    return;

  initialized = TRUE;

  icon_theme = gtk_icon_theme_get_default ();

  gtk_icon_theme_add_resource_path (icon_theme, "/org/ammoos/lighting/icons");
}

